<template>
  <div>
    <div key="random_c12242" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Are you self-employed?" :addons="false" class="info">
          <b-tooltip label="As per your tax statements" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-radio-button class="full-radio" :native-value="true" v-model="selfEmployed" @input="$emit('routechange')">
              <b-icon icon="check-circle"></b-icon>&thinsp;
              Yes I am
            </b-radio-button>
            <b-radio-button class="full-radio" :native-value="false" v-model="selfEmployed" @input="$emit('routechange')">
              <b-icon icon="times-circle"></b-icon>&thinsp;
              No I'm not
            </b-radio-button>
          </b-field>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Time on the job" :addons="false" class="info">
          <b-tooltip label="How long have you acted in your current capacity?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-input v-model="timeAtJob" type="text" expanded icon="calendar" v-debounce:800="checkYears"></b-input>
            <div class="control">
              <div class="button is-static">years</div>
            </div>
            <b-input v-model="timeAtJobMonths" type="text" expanded icon="calendar"></b-input>
            <div class="control">
              <div class="button is-static">months</div>
            </div>
          </b-field>
        </b-field>
      </div>
    </div>

    <div key="random_23sj34f" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Company name" :addons="false" class="info">
          <b-tooltip label="What is the registered name of the company you work for?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input ref="check1" v-model="companyName" expanded icon="briefcase" placeholder="I work for" required></b-input>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Time in the industry" :addons="false" class="info">
          <b-tooltip label="How long have worked in your current industry?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-input v-model="timeInIndustry" type="text" expanded icon="calendar"></b-input>
            <div class="control">
              <div class="button is-static">years</div>
            </div>
            <b-input v-model="timeInIndustryMonths" type="text" expanded icon="calendar"></b-input>
            <div class="control">
              <div class="button is-static">months</div>
            </div>
          </b-field>
        </b-field>
      </div>
    </div>

    <div key="random_cvk42" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Occupation" :addons="false" class="info">
          <b-tooltip label="What is your role at the company?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input ref="check2" v-model="occupation" expanded icon="user-tie" placeholder="I'm a" required></b-input>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Income" :addons="false" class="info">
          <b-tooltip label="Please input your annual or hourly rate. (Please enter the value in digits.)" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-field class="control" style="flex:1">
              <b-input ref="check4" v-model="income" placeholder="Amount in numbers" icon="dollar-sign" expanded required></b-input>
            </b-field>
            <b-field class="control">
              <b-select ref="check3" v-model="incomePer" icon="slash" placeholder="Per" required>
                <option value="hour">hour</option>
                <option value="year">year</option>
              </b-select>
            </b-field>
          </b-field>
        </b-field>
      </div>
    </div>

    <transition-group name="fadeUp" mode="out-in">
      <div key="random_lz9z9z" class="columns is-centered" v-if="additionalWorkFields">
        <div class="column is-one-third-desktop">
          <b-field label="Previous employer" :addons="false" class="info">
            <b-tooltip label="The legal name of your prior employer" position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-input v-model="previousEmployer" expanded icon="briefcase" placeholder="I worked for"></b-input>
          </b-field>
        </div>
        <div class="column is-one-third-desktop">
          <b-field label="Previous occupation" :addons="false" class="info">
            <b-tooltip label="Your occupation at the prior company" position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-input v-model="previousOccupation" expanded icon="user-tie" placeholder="I worked as"></b-input>
          </b-field>
        </div>
      </div>

      <div key="random_llkz1z" class="columns is-centered" v-if="additionalWorkFields">
        <div class="column is-one-third-desktop">
          <b-field label="Previous employer contact" :addons="false" class="info">
            <b-tooltip label="Any way to contact your prior employer. Phone number preferred." position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-input v-model="previousEmployerContact" expanded icon="phone-square" placeholder="Please contact"></b-input>
          </b-field>
        </div>
        <div class="column is-one-third-desktop">
          <b-field label="Time on the previous job" :addons="false" class="info">
            <b-tooltip label="How long did you work for the prior employer?" position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-field>
              <b-input v-model="timeAtPreviousJob" type="text" expanded icon="calendar"></b-input>
              <div class="control">
                <div class="button is-static">years</div>
              </div>
              <b-input v-model="timeAtPreviousJobMonths" type="text" expanded icon="calendar"></b-input>
              <div class="control">
                <div class="button is-static">months</div>
              </div>
            </b-field>
          </b-field>
        </div>
      </div>
    </transition-group>

    <address-block key="random_75lkj4j" :form="$store.state.EmploymentForm.address" icon="hotel" message="Address of the company you work for"></address-block>
  </div>
</template>

<script>
import addressBlock from "../components/address-block.vue";
import router from '../router';
export default {
  beforeRouteLeave(to, from, next) {
    let entries = [];
    for (const key in this.$refs) {
      if (this.$refs.hasOwnProperty(key) && key !== "checkAdd") {
        const ref = this.$refs[key];
        const checked = ref.checkHtml5Validity();
        entries.push(checked);
      }
    }

    if (entries.every(entry => entry === true)) {
      this.$store.commit("updateForm", {
        name: "EmploymentForm",
        data: this.$store.state.EmploymentForm
      });
      next();
    } else {
      next(false);
      this.$toast.open({
        duration: 2200,
        position: "is-bottom",
        message: `Please fill out the highlighted fields`,
        type: "is-danger"
      });
    }
  },
  data() {
    return {
      additionalWorkFields: false
    };
  },
  components: {
    addressBlock
  },
  methods: {
    checkYears() {
      this.timeAtJob < 3
        ? (this.additionalWorkFields = true)
        : (this.additionalWorkFields = false);
    }
  },
  computed: {
    selfEmployed: {
      get() {
        return this.$store.state.EmploymentForm.selfEmployed;
      },
      set(val) {
        this.$store.state.EmploymentForm.selfEmployed = val;
      }
    },
    occupation: {
      get() {
        return this.$store.state.EmploymentForm.occupation;
      },
      set(val) {
        this.$store.state.EmploymentForm.occupation = val;
      }
    },
    companyName: {
      get() {
        return this.$store.state.EmploymentForm.companyName;
      },
      set(val) {
        this.$store.state.EmploymentForm.companyName = val;
      }
    },
    employerName: {
      get() {
        return this.$store.state.EmploymentForm.employerName;
      },
      set(val) {
        this.$store.state.EmploymentForm.employerName = val;
      }
    },
    timeInIndustry: {
      get() {
        return this.$store.state.EmploymentForm.timeInIndustry;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeInIndustry = val;
      }
    },
    timeInIndustryMonths: {
      get() {
        return this.$store.state.EmploymentForm.timeInIndustryMonths;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeInIndustryMonths = val;
      }
    },
    timeAtPreviousJob: {
      get() {
        return this.$store.state.EmploymentForm.timeAtPreviousJob;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeAtPreviousJob = val;
      }
    },
    timeAtPreviousJobMonths: {
      get() {
        return this.$store.state.EmploymentForm.timeAtPreviousJobMonths;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeAtPreviousJobMonths = val;
      }
    },
    timeAtJobMonths: {
      get() {
        return this.$store.state.EmploymentForm.timeAtJobMonths;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeAtJobMonths = val;
      }
    },
    previousEmployer: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm
          .previousEmployer;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.previousEmployer = val;
      }
    },
    previousEmployerContact: {
      get() {
        return this.$store.state.EmploymentForm.previousEmployerContact;
      },
      set(val) {
        this.$store.state.EmploymentForm.previousEmployerContact = val;
      }
    },
    previousOccupation: {
      get() {
        return this.$store.state.EmploymentForm.previousOccupation;
      },
      set(val) {
        this.$store.state.EmploymentForm.previousOccupation = val;
      }
    },
    income: {
      get() {
        return this.$store.state.EmploymentForm.income;
      },
      set(val) {
        this.$store.state.EmploymentForm.income = val;
      }
    },
    incomePer: {
      get() {
        return this.$store.state.EmploymentForm.incomePer;
      },
      set(val) {
        this.$store.state.EmploymentForm.incomePer = val;
      }
    },
    timeInIndustry: {
      get() {
        return this.$store.state.EmploymentForm.timeInIndustry;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeInIndustry = val;
      }
    },
    timeAtJob: {
      get() {
        return this.$store.state.EmploymentForm.timeAtJob;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeAtJob = val;
      }
    }
  }
};
</script>
