<template>
  <div>
    <div key="random_01kjnsd0z0z" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Are you self-employed?" :addons="false" class="info">
          <b-tooltip label="As per your tax statements" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-radio-button class="full-radio" :native-value="true" v-model="selfEmployed" @input="$emit('routechange')">
              <b-icon icon="check-circle"></b-icon>&thinsp;
              Yes I am
            </b-radio-button>
            <b-radio-button class="full-radio" :native-value="false" v-model="selfEmployed" @input="$emit('routechange')">
              <b-icon icon="times-circle"></b-icon>&thinsp;
              No I'm not
            </b-radio-button>
          </b-field>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Registration date" :addons="false" class="info">
          <b-tooltip label="The date you registered/incorporated your business" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-datepicker v-model="registrationDate" icon="calendar-alt" placeholder="I Registered on"></b-datepicker>
        </b-field>
      </div>
    </div>

    <div class="columns" key="random_m0m0">
      <div class="column is-one-third-desktop is-offset-2-desktop">
        <b-field label="Business name" :addons="false" class="info">
          <b-tooltip label="What is the registered name of your business?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input ref="check1" v-model="businessName" expanded icon="user-tie" placeholder="My company is" required></b-input>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Business type" :addons="false" class="info">
          <b-tooltip label="What type of business do you operate?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-select v-model="businessType" expanded icon="building" placeholder="Most relevant">
            <option value="Sole Proprietor">Sole Proprietor</option>
            <option value="Corporation">Corporation</option>
            <option value="Partnership">Partnership</option>
          </b-select>
        </b-field>
      </div>
    </div>

    <div key="random_bvc94k1" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Net income" :addons="false" class="info">
          <b-tooltip label="How much do you keep annually? (Please enter amount in digits)" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input ref="check2" pattern="^[0-9]+(\.[0-9]{1,2})?$" type="number" v-model="netIncome" expanded icon="dollar-sign" placeholder="Amount in numbers" required></b-input>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Gross income" :addons="false" class="info">
          <b-tooltip label="How much does your business earn annually? (Please enter amount in digits)" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input ref="check3" pattern="^[0-9]+(\.[0-9]{1,2})?$" type="number" v-model="grossIncome" expanded icon="dollar-sign" placeholder="Amount in numbers" required></b-input>
        </b-field>
      </div>
    </div>

    <div key="random_77240vvg" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Occupation" :addons="false" class="info">
          <b-tooltip label="What is your role at your company?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input v-model="occupation" expanded icon="user-tie" placeholder="I'm a"></b-input>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Industry" :addons="false" class="info">
          <b-tooltip label="What industry fits your business best?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input v-model="industry" expanded icon="industry" placeholder="I'm in"></b-input>
        </b-field>
      </div>
    </div>

    <div key="random_z34f" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Time on the job" :addons="false" class="info">
          <b-tooltip label="How long have you owned this business?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-input v-model="timeAtJob" type="text" expanded icon="calendar"></b-input>
            <div class="control">
              <div class="button is-static">years</div>
            </div>
            <b-input v-model="timeAtJobMonths" type="text" expanded icon="calendar"></b-input>
            <div class="control">
              <div class="button is-static">months</div>
            </div>
          </b-field>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Time in the industry" :addons="false" class="info">
          <b-tooltip label="How long has your company operated in the current industry?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-input v-model="timeInIndustry" type="text" expanded icon="calendar"></b-input>
            <div class="control">
              <div class="button is-static">years</div>
            </div>
            <b-input v-model="timeInIndustryMonths" type="text" expanded icon="calendar"></b-input>
            <div class="control">
              <div class="button is-static">months</div>
            </div>
          </b-field>
        </b-field>
      </div>
    </div>

    <address-block key="random_75la1a14j" :form="$store.state.EmploymentForm.address" icon="hotel" message="Address of your business"></address-block>
  </div>
</template>

<script>
import addressBlock from "../components/address-block.vue";
export default {
  beforeRouteLeave(to, from, next) {
    let entries = [];
    for (const key in this.$refs) {
      if (this.$refs.hasOwnProperty(key) && key !== "checkAdd") {
        const ref = this.$refs[key];
        const checked = ref.checkHtml5Validity();
        entries.push(checked);
      }
    }

    if (entries.every(entry => entry === true)) {
      this.$store.commit("updateForm", {
        name: "EmploymentForm",
        data: this.$store.state.EmploymentForm
      });
      next();
    } else {
      next(false);
      this.$toast.open({
        duration: 2200,
        position: 'is-bottom',
        message: `Please fill out the highlighted fields`,
        type: "is-danger"
      });
    }
  },
  components: {
    addressBlock
  },
  computed: {
    selfEmployed: {
      get() {
        return this.$store.state.EmploymentForm.selfEmployed;
      },
      set(val) {
        this.$store.state.EmploymentForm.selfEmployed = val;
      }
    },
    netIncome: {
      get() {
        return this.$store.state.EmploymentForm.netIncome;
      },
      set(val) {
        this.$store.state.EmploymentForm.netIncome = val;
      }
    },
    industry: {
      get() {
        return this.$store.state.EmploymentForm.industry;
      },
      set(val) {
        this.$store.state.EmploymentForm.industry = val;
      }
    },
    grossIncome: {
      get() {
        return this.$store.state.EmploymentForm.grossIncome;
      },
      set(val) {
        this.$store.state.EmploymentForm.grossIncome = val;
      }
    },
    timeInIndustry: {
      get() {
        return this.$store.state.EmploymentForm.timeInIndustry;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeInIndustry = val;
      }
    },
    timeInIndustryMonths: {
      get() {
        return this.$store.state.EmploymentForm.timeInIndustryMonths;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeInIndustryMonths = val;
      }
    },
    timeAtJobMonths: {
      get() {
        return this.$store.state.EmploymentForm.timeAtJobMonths;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeAtJobMonths = val;
      }
    },
    timeAtJob: {
      get() {
        return this.$store.state.EmploymentForm.timeAtJob;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeAtJob = val;
      }
    },
    registrationDate: {
      get() {
        return new Date(this.$store.state.EmploymentForm.registrationDate);
      },
      set(val) {
        this.$store.state.EmploymentForm.registrationDate = val.toString();
      }
    },
    companyName: {
      get() {
        return this.$store.state.EmploymentForm.companyName;
      },
      set(val) {
        this.$store.state.EmploymentForm.companyName = val;
      }
    },
    occupation: {
      get() {
        return this.$store.state.EmploymentForm.occupation;
      },
      set(val) {
        this.$store.state.EmploymentForm.occupation = val;
      }
    },
    businessName: {
      get() {
        return this.$store.state.EmploymentForm.businessName;
      },
      set(val) {
        this.$store.state.EmploymentForm.businessName = val;
      }
    },
    businessType: {
      get() {
        return this.$store.state.EmploymentForm.businessType;
      },
      set(val) {
        this.$store.state.EmploymentForm.businessType = val;
      }
    }
  }
};
</script>