import Vue from 'vue'
import Router from 'vue-router'
import Home from './views/Home.vue'
import start from './views/start.vue'
import propertyForm from './views/property-form.vue'
import personalForm from './views/personal-form.vue'
import employmentForm from './views/employment-form.vue'
import coApplicantemploymentForm from './views/coApplicant-employment-form.vue'
import signaturesForm from './views/signatures-form.vue'
import coApplicant from './views/coApplicant-form.vue'
import selfEmployed from './views/employment-self.vue'
