import Vue from 'vue'
import Buefy from 'buefy'
import 'buefy/dist/buefy.css'
import App from './App.vue'
import router from './router'
import store from './store'
import './registerServiceWorker'
import axios from 'axios'
import vueDebounce from 'vue-debounce'
import '@fortawesome/fontawesome-free/css/fontawesome.min.css'
import '@fortawesome/fontawesome-free/css/solid.min.css'

// ####components####
import toPage from './components/page-button.vue'
import messageModal from './components/message-modal.vue'
import headings from './components/headings.vue'
import VueRouter from 'vue-router';
Vue.component('headings', headings)
Vue.component('message-modal', messageModal)
Vue.component('to-page', toPage)

Vue.use(vueDebounce)
Vue.use(Buefy, {
  defaultIconPack: 'fas',
  defaultContainerElement: '#forms-app',
  defaultDaynames: ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'],
  defaultDateParser: new Date().toLocaleDateString("en-US"),
  defaultDateFormatter: function(date) {
      return date.toLocaleDateString("en-US", {
        weekday: 'short', year: 'numeric', month: 'long', day: 'numeric'
      })
  }
})

new Vue({
  router,
  store,
  render: h => h(App)
}).$mount('#forms-app')

store.subscribe((mutation, state) => {
  if (mutation.type === 'updateForm') {
    localStorage.setItem('girafoState', JSON.stringify(state))
  }
  if (mutation.type === 'setBaseState') {
    localStorage.removeItem('girafoState')
  }
})

Vue.prototype.$http = axios

Vue.config.productionTip = true