<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="25" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Provide Us with Details on the Property You're Buying</p>
      <p slot="message">Please elaborate on the costs and details of the property you are looking to mortgage.</p>
      <p slot="message" class="is-size-5 is-size-6-mobile">This page inquires about the following form items:</p>
      <ul slot="list">
        <li>Realtor's quote price</li>
        <li>Your downpayment amount</li>
        <li>Your estimated annual property costs</li>
        <li>Any documents you've signed</li>
        <li v-if="$store.state.PropertyForm.offerMade">Terms of your contract</li>
      </ul>
    </message-modal>

    <div class="container">
      <div class="box">
        <div class="columns is-centered">
          <div class="column is-half is-one-third-desktop">
            <b-field label="Purchase price" :addons="false" class="info">
              <b-tooltip label="Quoted by your realtor or on the MLS listing. (Please enter amount in digits)" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input ref="check3" pattern="^[0-9]+(\.[0-9]{1,2})?$" v-model="purchasePrice" icon="dollar-sign" placeholder="Amount in numbers" required></b-input>
            </b-field>
          </div>
          <div class="column is-half is-one-third-desktop">
            <b-field label="Downpayment" :addons="false" class="info">
              <b-tooltip label="Maximum amount you can put down at this time. (Please enter amount in digits)" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input ref="check1" pattern="^[0-9]+(\.[0-9]{1,2})?$" v-model="downpayment" icon="dollar-sign" placeholder="Amount in numbers" required></b-input>
            </b-field>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-two-thirds-desktop">
            <div class="columns is-multiline">
              <div class="column is-half">
                <b-field label="Property taxes" :addons="false" class="info">
                  <b-tooltip label="Estimated annual cost based on property value. (Please enter amount in digits)" position="is-left" size="is-medium" type="is-dark" animated multilined>
                    <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                  </b-tooltip>
                  <b-input ref="check2" pattern="^[0-9]+(\.[0-9]{1,2})?$" v-model="propertyTaxes" icon="dollar-sign" placeholder="Amount in numbers" required></b-input>
                </b-field>
              </div>
              <div class="column is-half" v-if="$store.state.StartForm.occupancyType === 'Rental'">
                <b-field label="Expected rental income" :addons="false" class="info">
                  <b-tooltip label="What do you expect to charge per month? (Please enter amount in digits)" position="is-left" size="is-medium" type="is-dark" animated multilined>
                    <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                  </b-tooltip>
                  <b-input pattern="^[0-9]+(\.[0-9]{1,2})?$" icon="dollar-sign" placeholder="Amount in numbers" v-model="expectedRentalIncome"></b-input>
                </b-field>
              </div>
              <!-- <div class="column is-half" v-if="$store.state.StartForm.occupancyType === 'Rental' && $store.state.StartForm.propertyType === 'Condo'"> -->
              <div class="column is-half" v-if="$store.state.StartForm.propertyType === 'Condo'">
                <b-field label="Maintenance fee" :addons="false" class="info">
                  <b-tooltip label="What is your monthly maintenance fee? (Please enter amount in digits)" position="is-left" size="is-medium" type="is-dark" animated multilined>
                    <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                  </b-tooltip>
                  <b-input ref="check4" pattern="^[0-9]+(\.[0-9]{1,2})?$" icon="dollar-sign" placeholder="Amount in numbers" v-model="maintenanceFee" required></b-input>
                </b-field>
              </div>
              <div class="column is-half">
                <b-field label="Offer made" :addons="false" class="info">
                  <b-tooltip label="Have you signed the documents with your realtor?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                    <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                  </b-tooltip>
                  <b-select placeholder="With your realtor" expanded icon="handshake" v-model="offerMade">
                    <option :value="true">Yes</option>
                    <option :value="false">No</option>
                  </b-select>
                </b-field>
              </div>
            </div>
          </div>
        </div>

        <transition name="fadeUp" mode="out-in">
          <div class="columns is-centered" v-if="offerMade">
            <div class="column is-half is-one-third-desktop">
              <b-field label="Closing date" :addons="false" class="info">
                <b-tooltip label="Listed in the terms of your contract" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-datepicker v-model="closingDate" placeholder="Click for calendar" icon="calendar-alt"></b-datepicker>
              </b-field>
            </div>
            <div class="column is-half is-one-third-desktop">
              <b-field label="Financial conditions date" :addons="false" class="info">
                <b-tooltip label="Listed in the terms of your contract" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-datepicker v-model="conditionsDate" placeholder="Click for calendar" icon="calendar-alt"></b-datepicker>
              </b-field>
            </div>
          </div>
        </transition>

        <address-block ref="checkAdd" :form="$store.state.PropertyForm.address" message="Address of the property" icon="home" :disabled="true" :required="true"></address-block>

        <to-page next="/personal" text="Go to Personal Info Form"></to-page>
      </div>
    </div>
  </div>
</template>

<script>
import addressBlock from "../components/address-block.vue";
export default {
  beforeRouteLeave(to, from, next) {
    let entries = [];
    for (const key in this.$refs) {
      if (this.$refs.hasOwnProperty(key) && key !== "checkAdd") {
        const ref = this.$refs[key];
        const checked = ref.checkHtml5Validity();
        entries.push(checked);
      }
    }

    for (const addkey in this.$refs["checkAdd"].$refs) {
      if (this.$refs["checkAdd"].$refs.hasOwnProperty(addkey)) {
        const address = this.$refs["checkAdd"].$refs[addkey];
        const checked = address.checkHtml5Validity();
        entries.push(checked);
      }
    }

    if (entries.every(entry => entry === true)) {
      this.$store.commit("updateForm", {
        name: "PropertyForm",
        data: this.$store.state.PropertyForm
      });
      next();
    } else {
      next(false);
      this.$toast.open({
        duration: 2200,
        position: 'is-bottom',
        message: `Please fill out the highlighted fields`,
        type: "is-danger"
      });
    }
  },
  data() {
    return {
      page: "Page 2",
      heading: "Detailed Property Information",
      toggled: false
    };
  },
  computed: {
    offerMade: {
      get() {
        return this.$store.state.PropertyForm.offerMade;
      },
      set(val) {
        this.$store.state.PropertyForm.offerMade = val;
      }
    },
    closingDate: {
      get() {
        return new Date(this.$store.state.PropertyForm.closingDate);
      },
      set(val) {
        this.$store.state.PropertyForm.closingDate = val.toString();
      }
    },
    conditionsDate: {
      get() {
        return new Date(this.$store.state.PropertyForm.conditionsDate);
      },
      set(val) {
        this.$store.state.PropertyForm.conditionsDate = val.toString();
      }
    },
    purchasePrice: {
      get() {
        return this.$store.state.PropertyForm.purchasePrice;
      },
      set(val) {
        // this.$store.commit('updateForm', {
        //   name: 'PropertyForm',
        //   field: 'purchasePrice',
        //   data: val
        // });
        this.$store.state.PropertyForm.purchasePrice = val;
      }
    },
    maintenanceFee: {
      get() {
        return this.$store.state.PropertyForm.maintenanceFee;
      },
      set(val) {
        this.$store.state.PropertyForm.maintenanceFee = val;
      }
    },
    downpayment: {
      get() {
        return this.$store.state.PropertyForm.downpayment;
      },
      set(val) {
        this.$store.state.PropertyForm.downpayment = val;
      }
    },
    propertyTaxes: {
      get() {
        return this.$store.state.PropertyForm.propertyTaxes;
      },
      set(val) {
        this.$store.state.PropertyForm.propertyTaxes = val;
      }
    },
    expectedRentalIncome: {
      get() {
        return this.$store.state.PropertyForm.expectedRentalIncome;
      },
      set(val) {
        this.$store.state.PropertyForm.expectedRentalIncome = val;
      }
    }
  },
  components: {
    addressBlock
  }
};
</script>